 * 메뉴경로 : 물류(N)/국내 운영(협력)/차량정보사진
 * ASIS경로 : /dongwon-ntis-engine/src/main/webapp/bp/fbp/bi/vi/ez_104_01_02p.jsp
 * 작 성 자 : 유청아
 * 작 업 일 : 2026-03-23
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항

 * 수정이력 :
 *    - 2026-03-23      유청아    최초작성
 *    - 2026-04-13      이진우    T-6189 조치완료(파일첨부갯수10,화면타이틀 수정)
 */

scwin.params = null;
scwin.filePath = "";
scwin.fileName = "";
scwin.fileSize = "";

//-------------------------------------------------------------------------
// 페이지로드
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.params = $c.data.getParameter();

    if (!$c.util.isEmpty(scwin.params["attachFilePath"])) {
        scwin.filePath = scwin.params["attachFilePath"];
    }

    if (!$c.util.isEmpty(scwin.params["attachFileNm"])) {
        scwin.fileName = scwin.params["attachFileNm"];
    }
};

//-------------------------------------------------------------------------
// UDC값 초기화(scwin.onpageload 이후 세팅됨)
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {

};

//-------------------------------------------------------------------------
// 파일 업로드(UDC 저장버튼)
//-------------------------------------------------------------------------
